es.find({comments: {$all: ["nice", "Good"]}}) // does not care about order\n\ndb.articles.find({comments: {$elemMatch:{commentBy: "unknown", frequency: {$gt:3}}}})'})})}),Object(c.jsxs)("li",{children:["//iterating on cursor : ",Object(c.jsx)("br",{}),Object(c.jsx)("pre",{children:"cursor = db.articles.find({})\nwhile (cursor.hasNext()){\n  cursor.next()\n}"})]}),Object(c.jsxs)("li",{children:["//Sorting cursor results :",Object(c.jsx)("div",{style:{maxWidth:"250px",overflowX:"scroll"},children:Object(c.jsx)("pre",{children:'// 1 means ASC, -1 means DESC\ndb.persons.find().sort({"age": 1})\n\n// ASC by age then DESC by name\ndb.persons.find().sort({"age": 1, "name":-1})\n\n//Skipping and limiting cursor results\ndb.persons.find().skip(100)\n\ndb.persons.find().limit(100)\n'})}),"Logical Order -> sort, then skip then limit"]})]}),Object(c.jsxs)("ul",{children:["Projection",Object(c.jsx)("li",{children:Object(c.jsx)("div",{style:{maxWidth:"250px",overflowX:"scroll"},children:Object(c.jsx)("pre",{children:'db.persons.find({hobbies: "cooking"}, {"hobbies.$": 1})\ndb.persons.find({hobbies: "cooking"}, {hobbies : {$elemMatch: {$eq : "sports"}}}) // documents which have cooking and only show sports in hobbies\n\ndb.persons.find({hobbies: "cooking"}, {hobbies : {$slice: 2}}) // documents with first 2 hobbies\ndb.persons.find({hobbies: "cooking"}, {hobbies : {$slice: [1, 2]}}) // documents will skip first hobby and show us next 2 hobbies\n'})})})]}),Object(c.jsxs)("ul",{children:["Update operators",Object(c.jsx)("li",{children:Object(c.jsx)("div",{style:{maxWidth:"250px",overflowX:"scroll"},children:Object(c.jsx)("pre",{children:'db.articles.updateOne({title: "mongo"}, {$inc: {likes:1}}})\ndb.articles.updateOne({title: "mongo"}, {$dec: {likes:1}}})\nor\ndb.articles.updateOne({title: "mongo"}, {$inc: {likes:-1}}})\n\ndb.articles.updateOne({title: "mongo"}, {$inc: {likes:1}, $set: {isARated: true}}})  // increments likes by 1 and sets isARated to true\ndb.articles.updateOne({t